4132       PrevOrder.resize(Sz);
4133       std::iota(PrevOrder.begin(), PrevOrder.end(), 0);
4134     } else {
4135       PrevOrder.swap(Order);
4136     }
4137     Order.assign(Sz, Sz);
4138     for (unsigned I = 0; I < Sz; ++I)
4139       if (Mask[I] != PoisonMaskElem)
4140         Order[I] = PrevOrder[Mask[I]];
4141     if (all_of(enumerate(Order), [&](const auto &Data) {
4142           return Data.value() == Sz || Data.index() == Data.value();
4143         })) {
4144       Order.clear();
4145       return;
4146     }
4147     fixupOrderingIndices(Order);
4148     return;
4149   }
4150   SmallVector<int> MaskOrder;
4151   if (Order.empty()) {
4152     MaskOrder.resize(Sz);
4153     std::iota(MaskOrder.begin(), MaskOrder.end(), 0);
4154   } else {
4155     inversePermutation(Order, MaskOrder);
4156   }
4157   reorderReuses(MaskOrder, Mask);
4158   if (ShuffleVectorInst::isIdentityMask(MaskOrder, Sz)) {
