16270 void SLPVectorizerPass::collectSeedInstructions(BasicBlock *BB) {
16271   // Initialize the collections. We will make a single pass over the block.
16272   Stores.clear();
16273   GEPs.clear();
16274 
16275   // Visit the store and getelementptr instructions in BB and organize them in
16276   // Stores and GEPs according to the underlying objects of their pointer
16277   // operands.
16278   for (Instruction &I : *BB) {
16279     // Ignore store instructions that are volatile or have a pointer operand
16280     // that doesn't point to a scalar type.
16281     if (auto *SI = dyn_cast<StoreInst>(&I)) {
16282       if (!SI->isSimple())
16283         continue;
16284       if (!isValidElementType(SI->getValueOperand()->getType()))
16285         continue;
16286       Stores[getUnderlyingObject(SI->getPointerOperand())].push_back(SI);
16287     }
16288 
16289     // Ignore getelementptr instructions that have more than one index, a
16290     // constant index, or a pointer operand that doesn't point to a scalar
16291     // type.
16292     else if (auto *GEP = dyn_cast<GetElementPtrInst>(&I)) {
16293       if (GEP->getNumIndices() != 1)
16294         continue;
16295       Value *Idx = GEP->idx_begin()->get();
16296       if (isa<Constant>(Idx))
16297         continue;
16298       if (!isValidElementType(Idx->getType()))
16299         continue;
16300       if (GEP->getType()->isVectorTy())
16301         continue;
16302       GEPs[GEP->getPointerOperand()].push_back(GEP);
16303     }
16304   }
